    }

    public Type forApp(App a) { throw new TypeException("Application type checking not yet implemented"); }
    public Type forMap(Map m) { throw new TypeException("Map type checking not yet implemented"); }
    public Type forIf(If i) { throw new TypeException("If type checking not yet implemented"); }
    public Type forLet(Let l) { throw new TypeException("Let type checking not yet implemented"); }
    public Type forBlock(Block b) { throw new TypeException("Block type checking not yet implemented"); }

    /** Check if two types are equal. */
    private boolean typeEq(Type t1, Type t2) {
      if (t1 == IntType.ONLY && t2 == IntType.ONLY) return true;
      if (t1 == BoolType.ONLY && t2 == BoolType.ONLY) return true;
      if (t1 == UnitType.ONLY && t2 == UnitType.ONLY) return true;
      if (t1 instanceof ListType && t2 instanceof ListType) {
