    public Type forApp(App a) {
      // For now, just skip type checking for applications
      return IntType.ONLY; // placeholder
    }

    public Type forMap(Map m) {
      // For now, just skip type checking for maps
      return IntType.ONLY; // placeholder
    }

    public Type forIf(If i) {
      Type testType = checkExp(i.test(), typeEnv);
      if (!typeEq(testType, BoolType.ONLY))
        throw new TypeException("if condition must be bool, got " + testType);
      Type conseqType = checkExp(i.conseq(), typeEnv);
      Type altType = checkExp(i.alt(), typeEnv);
      if (!typeEq(conseqType, altType))
        throw new TypeException("if branches have different types: " + conseqType + " vs " + altType);
      return conseqType;
    }

    public Type forLet(Let l) {
      // For now, just skip type checking for lets
      return IntType.ONLY; // placeholder
    }

    public Type forBlock(Block b) {
      Type resultType = null;
      for (AST exp : b.exps()) {
        resultType = checkExp(exp, typeEnv);
      }
      return resultType != null ? resultType : UnitType.ONLY;
    }
  }

  /** Check if two types are equal. */
  private boolean typeEq(Type t1, Type t2) {
    if (t1 == IntType.ONLY && t2 == IntType.ONLY) return true;
    if (t1 == BoolType.ONLY && t2 == BoolType.ONLY) return true;
    if (t1 == UnitType.ONLY && t2 == UnitType.ONLY) return true;
